before_code:
library IEEE;
use IEEE.STD_LOGIC_1164.ALL;

entity comparator_64bit is
  port (
    data_a : in std_logic_vector(63 downto 0);
    data_b : in std_logic_vector(63 downto 0);
    equal : out std_logic;
    greater : out std_logic;
    less : out std_logic
  );
end comparator_64bit;

architecture RTL of comparator_64bit is
begin
  process(data_a) is
  begin
    if data_a = data_b then
      equal <= '1';
      greater <= '0';
      less <= '0';
    elsif data_a > data_b then
      equal <= '0';
      greater <= '1';
      less <= '0';
    else
      equal <= '0';
      greater <= '0';
      less <= '1';
    end if;
  end process;
end RTL;

